import jwt
from pydantic import BaseModel
from datetime import datetime, timedelta

class Token(BaseModel):
    sub: str
    exp: int

def decode_token(token: str) -> dict:
    try:
        token_data = jwt.decode(token, algorithms=['HS256'])
        return token_data
    except Exception as e:
        print(f"Error decoding token: {str(e)}")
        return {}

def verify_token(token: str) -> bool:
    try:
        decoded_token = decode_token(token)
        token_expires_at = datetime.fromtimestamp(decoded_token['exp'])
        current_datetime = datetime.now()
        if token_expires_at > current_datetime + timedelta(minutes=5):
            return True
        else:
            return False
    except Exception as e:
        print(f"Error verifying token: {str(e)}")
        return False

def get_token_details(token: str) -> dict:
    try:
        decoded_token = decode_token(token)
        if 'sub' in decoded_token:
            return {'token': token, 'user_id': decoded_token['sub']}
        else:
            return {}
    except Exception as e:
        print(f"Error getting token details: {str(e)}")
        return {}